protected container activeOverviewRecords()
{
    ITMTmpCreatorTable tmpShipCreatorTableSelected;
    container overviewRecords;

    tmpShipCreatorTableSelected = ITMTmpCreatorTable_ds.getFirst(true, false) ?
                                  ITMTmpCreatorTable_ds.getFirst(true, false) :
                                  ITMTmpCreatorTable_ds.cursor();

    while (tmpShipCreatorTableSelected)
    {
        overviewRecords += [[tmpShipCreatorTableSelected.InventTransType,
                             tmpShipCreatorTableSelected.InventTransRefId,
                             tmpShipCreatorTableSelected.DateStatus,
                             tmpShipCreatorTableSelected.InventSiteId,
                             tmpShipCreatorTableSelected.InventLocationId,
                             tmpShipCreatorTableSelected.ShipDataArea]];

        tmpShipCreatorTableSelected = ITMTmpCreatorTable_ds.getNext();
    }

    return overviewRecords;
}

public void close()
{
    super();

    element.saveLastOptions();

    xSysLastValue::saveLast(this);
}

public boolean canClose()
{
    boolean ret;

    ret = super();        

    if (ret
        && shipEditorForm.isLineExistInBucket(ITMTmpCreatorLine)
        && Box::yesNo(strFmt("@InboundTransportationManagement:VoyageEditorConfirmClose", shipTableForm.parmITMTable().ShipId), DialogButton::No) == DialogButton::No)
    {
        ret = false;
    }

    return ret;
}

protected void deleteSetup(NoYes _reInitialize = true)
{
    List tmpList = List::create(setupList.pack());
    ListEnumerator le = tmpList.getEnumerator();

    setupList = new List(Types::Container);
    while (le.moveNext())
    {
        if (conPeek(le.current(), 1) != setupName)
        {
            setupList.addEnd(le.current());
        }
    }

    if (!_reInitialize)
    {
        return;
    }

    le = setupList.getEnumerator();
    le.moveNext();
    if (le.current())
    {
        element.unpackOptions(conPeek(le.current(), 2));
    }
    element.initSetupOptions();
}

