public void fillTables()
{
    if (!generateDataManually)
    {
        ETGITMCreatorTableGeneration::generateFromForm(
            ITMTmpCreatorTable,
            ITMTmpCreatorLine,
            shipCreatorOptions.pack());

        ITMTmpCreatorLineOtherDates.setTmpData(ITMTmpCreatorLine);

        ITMTmpCreatorTable_ds.executeQuery();
    }
}

public void fillData(container _tableSetData, container _lineSetData)
{
    ttsbegin;
    delete_from ITMTmpCreatorTable;

    ITMTmpCreatorLine itmTmpCreatorLineLocal;
    itmTmpCreatorLineLocal.setTmpData(ITMTmpCreatorLine);
    delete_from itmTmpCreatorLineLocal;

    Set tableSet = Set::create(_tableSetData);
    SetEnumerator tableEnumerator = tableSet.getEnumerator();
    while (tableEnumerator.moveNext())
    {
        ITMTmpCreatorTable.data(tableEnumerator.current());
        ITMTmpCreatorTable.insert();
    }

    Set lineSet = Set::create(_lineSetData);
    SetEnumerator lineEnumerator = lineSet.getEnumerator();
    while (lineEnumerator.moveNext())
    {
        ITMTmpCreatorLine.data(lineEnumerator.current());
        ITMTmpCreatorLine.insert();
    }

    ITMTmpCreatorLineOtherDates.setTmpData(ITMTmpCreatorLine);
    ttscommit;

    ITMTmpCreatorTable_ds.executeQuery();
}

