public void init()
{
    shipCreatorOptions = ITMCreatorOptions::construct();
    generateDataManually = ITMEditorGenerateDataManuallyFeature::isEnabled();

    super();

    editCompany.visible(false);
    shipCreatorOptions.parmCompany(curExt());
    LineGrid_ShipDataArea.allowEdit(false);
    ITMTmpCreatorLineOtherDates_ShipDataArea.allowEdit(false);

    element.design().viewEditMode(ViewEditMode::Edit);

    if (element.args().caller() is ETGITMTableFormOutbound || element.args().menuItemName() == menuitemdisplaystr(ETGITMEditorOutbound))
    {
        shipTableForm = element.args().caller();

        this.setTitleText();

        shipEditorForm = ETGITMEditorFormHandlerOut::newFromForm(element);

      //  xSysLastValue::getLast(this);
        xSysLastValue::getLast(this);

        if (shipTableForm.parmSalesTable())
        {
           // todo test
           this.initFromSalesTable(shipTableForm.parmSalesTable());
        }
    }
    else
    {
        throw error("@SYS22539");
    }            

    element.updateDesign(InventDimFormDesignUpdate::Init);
}

