public void initParmDefault()
{
    setupList = new List(Types::Container);

    setupName = "@SYS1657";   // Inquiry
    shipCreatorOptions.parmDaysBefore('');
    shipCreatorOptions.parmDaysAfter('');
    shipCreatorOptions.parmInclPurch(NoYes::Yes);
    shipCreatorOptions.parmInclTransfer(NoYes::Yes);
    setupList.addStart([setupName, shipCreatorOptions.pack()]);

    setupName = "@SYS57439";  // Today
    shipCreatorOptions.parmDaysBefore(int2str(0));
    shipCreatorOptions.parmDaysAfter(int2str(0));
    shipCreatorOptions.parmInclPurch(NoYes::Yes);
    shipCreatorOptions.parmInclTransfer(NoYes::Yes);
    setupList.addStart([setupName, shipCreatorOptions.pack()]);

    setupName = LastOptions;
    setupList.addEnd([setupName, shipCreatorOptions.pack()]);

    element.initSetupOptions();
}

protected void initSetupOptions()
{
    ListEnumerator  le = setupList.getEnumerator();
    Name setupNameTmp;

    setupOptions.clear();

    while (le.moveNext())
    {
        setupNameTmp = conPeek(le.current(), 1);
        setupOptions.add(setupNameTmp);

        if (setupNameTmp == setupName)
        {
            element.unpackOptions(conPeek(le.current(), 2));
        }
    }
    setupOptions.selectText(setupName);
}

