protected void optionsSave(Name _name)
{
    Name name;

    if (_name)
    {
        name = _name;
    }
    else
    {
        Dialog saveDialog = new Dialog();
        saveDialog.caption("@SYS12229");

        DialogField dialogField = saveDialog.addField(extendedTypeStr(Name), "@SYS7399", "@SYS104730");
        if (!saveDialog.run())
        {
            return;
        }
        name = dialogField.value();
    }

    if (name)
    {
        NoYes isReplaced = NoYes::No;
        List tmpList = List::create(setupList.pack());
        setupList = new List(Types::Container);

        ListEnumerator le = tmpList.getEnumerator();
        while (le.moveNext())
        {
            Name setupNameTmp = conPeek(le.current(), 1);

            if (name != setupNameTmp)
            {
                setupList.addEnd(le.current());
            }
            else
            {
                isReplaced = NoYes::Yes;

                if (!_name && Box::yesNo("@SYS40529", DialogButton::No) == DialogButton::No)
                {
                    setupList.addEnd(le.current());
                }
                else
                {
                    setupName = name;
                    setupList.addEnd([setupName, shipCreatorOptions.pack()]);
                }
            }
        }

        if (!isReplaced)
        {
            setupName = name;
            setupList.addEnd([setupName, shipCreatorOptions.pack()]);
        }

        element.initSetupOptions();
    }
}

