public boolean unpack(container _packedClass)
{
    Version                 version = RunBase::getVersion(_packedClass);
    container               packedList;

    switch (version)
    {
        case CurrentVersion:
            [version,#CurrentList, packedList] = _packedClass;
            setupList = List::create(packedList);
            element.initSetupOptions();
            break;

        default:
            return false;
    }

    return true;
}

protected void unpackOptions(container _packedOptions)
{
    shipCreatorOptions.unpack(_packedOptions);

    daysBeforeCtrl.update();
    daysAfterCtrl.update();
    warehouseRangeCtrl.update();
    editVendRef.update();
  //  custVendACCtrl.update();
   // editCustAccount.update();
    editItemId.update();
    editDlvModeId.update();

    element.fillTables();
}

protected void updateDesign(InventDimFormDesignUpdate _mode)
{
    switch (_mode)
    {
        case InventDimFormDesignUpdate::Init:
            if (!inventDimFormSetup)
            {
                inventDimFormSetup  = InventDimCtrl_Frm::newFromFormOutboundETG(element);
            }
            inventDimFormSetup.parmSkipOnHandLookUp(true);

            if (generateDataManually)
            {
                FiltersTabPage.caption("@InboundTransportationManagement:ITMEditorDataGenerationCriteria");
            }
            else
            {
                GenerateData.visible(false);
            }

        case InventDimFormDesignUpdate::Active:
            inventDimFormSetup.formSetControls(true);
            break;

        default: 
            throw error(strFmt("@SYS54195", funcName()));
    }
}

