public void init()
{
    super();

    ITMTmpCreatorTable.setTmpData(ITMTmpCreatorTable::createOnServerOutboundETG());

    this.filterNoOfLines();
}

private void filterNoOfLines()
{
    QueryBuildRange queryBuildRange = ITMTmpCreatorTable_ds.query().dataSourceTable(tableNum(ITMTmpCreatorTable)).addRange(fieldNum(ITMTmpCreatorTable, NoOfLines));
    queryBuildRange.value(SysQuery::valueNot(0));
}

public void write()
{
    ttsBegin;

    if (ITMTmpCreatorTable.Selected != ITMTmpCreatorTable.orig().Selected)
    {
        ITMTmpCreatorLine::updateSelected(ITMTmpCreatorLine,
                                               ITMTmpCreatorTable.Selected,
                                               ITMTmpCreatorTable.InventTransType,
                                               ITMTmpCreatorTable.InventTransRefId,
                                               ITMTmpCreatorTable.DateStatus,
                                               ITMTmpCreatorTable.ShipDataArea);

        shipEditorForm.refreshFactBoxShipmentTotals(ITMTmpCreatorLine);
    }

    super();

    ttsCommit;
}

public int active()
{
    int ret;

    ret = super();

    ITMTmpCreatorLine::updateHeaderMarked(ITMTmpCreatorLine, element.activeOverviewRecords());

    this.filterDateStatus();

    shipEditorForm.refreshFactBoxReceiptDetails(ITMTmpCreatorTable);

    return ret;
}

protected void filterDateStatus()
{
    ITMTmpCreatorLine_ds.query().dataSourceTable(tableNum(ITMTmpCreatorLine)).clearRange(fieldNum(ITMTmpCreatorLine, DateStatus));
    QueryBuildRange queryBuildRange = ITMTmpCreatorLine_ds.query().dataSourceNo(1).addRange(fieldNum(ITMTmpCreatorLine, DateStatus));
    queryBuildRange.value(queryValue(ITMTmpCreatorTable.DateStatus));
    queryBuildRange.status(RangeStatus::Hidden);

    ITMTmpCreatorLine_ds.executeQuery();

    ITMTmpCreatorLineOtherDates_ds.query().dataSourceTable(tableNum(ITMTmpCreatorLine)).clearRange(fieldNum(ITMTmpCreatorLine, DateStatus));
    QueryBuildRange qbr = ITMTmpCreatorLineOtherDates_ds.query().dataSourceNo(1).addRange(fieldNum(ITMTmpCreatorLine, DateStatus));
    qbr.value("@SYS112371" + queryValue(ITMTmpCreatorTable.DateStatus));
    qbr.status(RangeStatus::Hidden);

    ITMTmpCreatorLineOtherDates_ds.executeQuery();
}

public void executeQuery()
{
    super();

    ITMTmpCreatorLine::updateHeaderMarked(ITMTmpCreatorLine, conNull());
    ITMTmpCreatorLine_ds.executeQuery();

    ITMTmpCreatorLine::updateHeaderMarked(ITMTmpCreatorLineOtherDates, conNull());
    ITMTmpCreatorLineOtherDates_ds.executeQuery();
}

