public void init()
{
    QueryBuildRange queryBuildRange, qbrAddToBucket;

    super();

    ITMTmpCreatorLine.setTmpData(ITMTmpCreatorLine::createOnServerOutboundETG());
    queryBuildRange = ITMTmpCreatorLine_ds.query().dataSourceNo(1).addRange(fieldNum(ITMTmpCreatorLine, HeaderMarked));
    queryBuildRange.value(queryValue(NoYes::Yes));
    queryBuildRange.status(RangeStatus::Hidden);

    qbrAddToBucket = ITMTmpCreatorLine_ds.query().dataSourceNo(1).addRange(fieldNum(ITMTmpCreatorLine, AddedToBucket));
    qbrAddToBucket.value(queryValue(NoYes::No));
    qbrAddToBucket.status(RangeStatus::Hidden);

}

public void write()
{
    ITMTmpCreatorTable tmpShipCreatorTable;
    ITMTmpCreatorTable tmpShipCreatorTableSelected;
    ITMTmpCreatorLine  tmpShipCreatorLine;
    NoYes origSelected = ITMTmpCreatorLine.orig().Selected;
    NoYes anyOverviewChanged = NoYes::No;

    super();

    if (origSelected != ITMTmpCreatorLine.Selected)
    { 
        tmpShipCreatorLine.setTmpData(ITMTmpCreatorLine);

        tmpShipCreatorTable.setTmpData(ITMTmpCreatorTable);

        ttsBegin;
        select firstOnly forUpdate tmpShipCreatorTable
            where tmpShipCreatorTable.InventTransType      == ITMTmpCreatorLine.InventTransType
            && tmpShipCreatorTable.InventTransRefId     == ITMTmpCreatorLine.InventTransRefId
            && tmpShipCreatorTable.DateStatus           == ITMTmpCreatorLine.DateStatus
            && tmpShipCreatorTable.ShipDataArea         == ITMTmpCreatorLine.ShipDataArea
            && tmpShipCreatorTable.Selected             == origSelected
                notexists join tmpShipCreatorLine
                    where tmpShipCreatorLine.InventTransType  == ITMTmpCreatorLine.InventTransType
                    && tmpShipCreatorLine.InventTransRefId == ITMTmpCreatorLine.InventTransRefId
                    && tmpShipCreatorLine.DateStatus == ITMTmpCreatorLine.DateStatus
                    && tmpShipCreatorLine.ShipDataArea == ITMTmpCreatorLine.ShipDataArea
                    && tmpShipCreatorLine.RecId != ITMTmpCreatorLine.RecId
                    && tmpShipCreatorLine.InventQty > 0
                    && tmpShipCreatorLine.Selected == origSelected;

        if (tmpShipCreatorTable.RecId)
        {
            tmpShipCreatorTable.Selected = ITMTmpCreatorLine.Selected;
            tmpShipCreatorTable.write();
            anyOverviewChanged = NoYes::Yes;
        }

        ttsCommit;

        ITMTmpCreatorTable_ds.reread();

        if (anyOverviewChanged)
        {
            Set recIdSet = new Set(Types::Int64);

            tmpShipCreatorTableSelected = ITMTmpCreatorTable_ds.getFirst(true);
            while (tmpShipCreatorTableSelected)
            {
                recIdSet.add(tmpShipCreatorTableSelected.RecId);
                tmpShipCreatorTableSelected = ITMTmpCreatorTable_ds.getNext();
            }
        }

        shipEditorForm.refreshFactBoxShipmentTotals(ITMTmpCreatorLine);
    }
}

